func testPromptTypesUpdate(t *testing.T) {
	t.Parallel()

	if 0 == len(promptTypePrimaryKeyColumns) {
		t.Skip("Skipping table with no primary key columns")
	}
	if len(promptTypeAllColumns) == len(promptTypePrimaryKeyColumns) {
		t.Skip("Skipping table with only primary key columns")
	}

	seed := randomize.NewSeed()
	var err error
	o := &PromptType{}
	if err = randomize.Struct(seed, o, promptTypeDBTypes, true, promptTypeColumnsWithDefault...); err != nil {
		t.Errorf("Unable to randomize PromptType struct: %s", err)
	}

	ctx := context.Background()
	tx := MustTx(boil.BeginTx(ctx, nil))
	defer func() { _ = tx.Rollback() }()
	if err = o.Insert(ctx, tx, boil.Infer()); err != nil {
		t.Error(err)
	}

	count, err := PromptTypes().Count(ctx, tx)
	if err != nil {
		t.Error(err)
	}

	if count != 1 {
		t.Error("want one record, got:", count)
	}

	if err = randomize.Struct(seed, o, promptTypeDBTypes, true, promptTypePrimaryKeyColumns...); err != nil {
		t.Errorf("Unable to randomize PromptType struct: %s", err)
	}

	if rowsAff, err := o.Update(ctx, tx, boil.Infer()); err != nil {
		t.Error(err)
	} else if rowsAff != 1 {
		t.Error("should only affect one row but affected", rowsAff)
	}
}

func testPromptTypesSliceUpdateAll(t *testing.T) {
	t.Parallel()

	if len(promptTypeAllColumns) == len(promptTypePrimaryKeyColumns) {
		t.Skip("Skipping table with only primary key columns")
	}

	seed := randomize.NewSeed()
	var err error
	o := &PromptType{}
	if err = randomize.Struct(seed, o, promptTypeDBTypes, true, promptTypeColumnsWithDefault...); err != nil {
		t.Errorf("Unable to randomize PromptType struct: %s", err)
	}

	ctx := context.Background()
	tx := MustTx(boil.BeginTx(ctx, nil))
	defer func() { _ = tx.Rollback() }()
	if err = o.Insert(ctx, tx, boil.Infer()); err != nil {
		t.Error(err)
	}

	count, err := PromptTypes().Count(ctx, tx)
	if err != nil {
		t.Error(err)
	}

	if count != 1 {
		t.Error("want one record, got:", count)
	}

	if err = randomize.Struct(seed, o, promptTypeDBTypes, true, promptTypePrimaryKeyColumns...); err != nil {
		t.Errorf("Unable to randomize PromptType struct: %s", err)
	}

	// Remove Primary keys and unique columns from what we plan to update
	var fields []string
	if strmangle.StringSliceMatch(promptTypeAllColumns, promptTypePrimaryKeyColumns) {
		fields = promptTypeAllColumns
	} else {
		fields = strmangle.SetComplement(
			promptTypeAllColumns,
			promptTypePrimaryKeyColumns,
		)
	}

	value := reflect.Indirect(reflect.ValueOf(o))
	typ := reflect.TypeOf(o).Elem()
	n := typ.NumField()

	updateMap := M{}
	for _, col := range fields {
		for i := 0; i < n; i++ {
			f := typ.Field(i)
			if f.Tag.Get("boil") == col {
				updateMap[col] = value.Field(i).Interface()
			}
		}
	}

	slice := PromptTypeSlice{o}
	if rowsAff, err := slice.UpdateAll(ctx, tx, updateMap); err != nil {
		t.Error(err)
	} else if rowsAff != 1 {
		t.Error("wanted one record updated but got", rowsAff)
	}
}

